const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, PutCommand, GetCommand } = require('@aws-sdk/lib-dynamodb');
const bcrypt = require('bcryptjs');
const crypto = require('crypto');

const client = new DynamoDBClient({});
const docClient = DynamoDBDocumentClient.from(client);

const TABLE_NAME = process.env.USERS_TABLE_NAME;
const SALT_ROUNDS = 12;

const EMAIL_REGEX = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;

function validateEmail(email) {
  if (!email || typeof email !== 'string') {
    return false;
  }
  
  if (email.length > 254) {
    return false;
  }
  
  return EMAIL_REGEX.test(email);
}

function validatePassword(password) {
  if (!password || typeof password !== 'string') {
    return false;
  }
  
  if (password.length < 8 || password.length > 128) {
    return false;
  }
  
  const hasUpperCase = /[A-Z]/.test(password);
  const hasLowerCase = /[a-z]/.test(password);
  const hasNumbers = /\d/.test(password);
  const hasSpecialChar = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/.test(password);
  
  return hasUpperCase && hasLowerCase && hasNumbers && hasSpecialChar;
}

function sanitizeForLogging(data) {
  const sanitized = { ...data };
  if (sanitized.password) {
    sanitized.password = '[REDACTED]';
  }
  if (sanitized.passwordHash) {
    sanitized.passwordHash = '[REDACTED]';
  }
  return sanitized;
}

exports.handler = async (event) => {
  const headers = {
    'Content-Type': 'application/json',
    'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'X-XSS-Protection': '1; mode=block'
  };

  try {
    if (event.httpMethod !== 'POST') {
      return {
        statusCode: 405,
        headers,
        body: JSON.stringify({ error: 'Method not allowed' })
      };
    }

    if (!event.body) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'Request body is required' })
      };
    }

    let body;
    try {
      body = JSON.parse(event.body);
    } catch (e) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ error: 'Invalid JSON in request body' })
      };
    }

    const { email, password } = body;

    if (!validateEmail(email)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ 
          error: 'Invalid email format. Email must be a valid email address.' 
        })
      };
    }

    if (!validatePassword(password)) {
      return {
        statusCode: 400,
        headers,
        body: JSON.stringify({ 
          error: 'Invalid password. Password must be 8-128 characters and contain uppercase, lowercase, number, and special character.' 
        })
      };
    }

    const normalizedEmail = email.toLowerCase().trim();

    const existingUser = await docClient.send(
      new GetCommand({
        TableName: TABLE_NAME,
        Key: { email: normalizedEmail }
      })
    );

    if (existingUser.Item) {
      return {
        statusCode: 409,
        headers,
        body: JSON.stringify({ error: 'User already exists' })
      };
    }

    const passwordHash = await bcrypt.hash(password, SALT_ROUNDS);

    const userId = crypto.randomUUID();
    const timestamp = new Date().toISOString();

    const user = {
      userId,
      email: normalizedEmail,
      passwordHash,
      createdAt: timestamp,
      updatedAt: timestamp,
      emailVerified: false
    };

    await docClient.send(
      new PutCommand({
        TableName: TABLE_NAME,
        Item: user,
        ConditionExpression: 'attribute_not_exists(email)'
      })
    );

    console.log('User registered successfully:', sanitizeForLogging({ userId, email: normalizedEmail }));

    return {
      statusCode: 201,
      headers,
      body: JSON.stringify({
        message: 'User registered successfully',
        userId,
        email: normalizedEmail
      })
    };

  } catch (error) {
    console.error('Registration error:', sanitizeForLogging({
      message: error.message,
      name: error.name
    }));

    if (error.name === 'ConditionalCheckFailedException') {
      return {
        statusCode: 409,
        headers,
        body: JSON.stringify({ error: 'User already exists' })
      };
    }

    return {
      statusCode: 500,
      headers,
      body: JSON.stringify({ error: 'Internal server error' })
    };
  }
};